+    private async Task<AuthenticationResponse> RegisterAsync()
+    {
+        var suffix = Guid.NewGuid().ToString("N");
+        using var response = await _client.PostAsJsonAsync("/api/auth/register", new RegisterUserCommand($"User {suffix}",
