                  >
                    <div>
                      <p className="font-medium">
                        {productNames.get(balance.productId) ??
                          balance.productId}
                      </p>
                      <p className="text-sm text-muted-foreground">
                        {warehouseNames.get(balance.warehouseId) ??
                          balance.warehouseId}
                      </p>
